const input = $input.first().json || {};

const scope = String(input.scope || 'profile').trim().toLowerCase();
const operation = String(input.operation || 'get').trim().toLowerCase();
const source = String(input.source || '').trim();
const referenceText = String(input.reference_text || '')
  .trim()
  .replace(/^["']+|["']+$/g, '');
const exactId = String(input.exact_id || '').trim();
const phoneNo = String(input.phone_no || '').trim();
const platformUserId = String(input.platform_user_id || '').trim();
const rawTenantId = Array.isArray(input.tenant_id) ? input.tenant_id[0] : input.tenant_id;
const tenantId = String(rawTenantId || '').trim();
const rawBusinessId = Array.isArray(input.business_id) ? input.business_id[0] : input.business_id;
const businessId = String(rawBusinessId || '').trim();
const limit = Math.max(1, Math.min(Number(input.limit || 5), 20));

return [{
  json: {
    scope,
    operation,
    reference_text: referenceText,
    exact_id: exactId,
    tenant_id: tenantId,
    business_id: businessId,
    phone_no: phoneNo,
    platform_user_id: platformUserId,
    source,
    limit
  }
}];

const input = $('Normalize Request').first().json;

return [{
  json: {
    success: true,
    scope: input.scope,
    operation: input.operation,
    identity: {
      business_id: input.business_id || null,
      resolved: !!input.business_id,
      matched_by: 'business_id'
    },
    found: false,
    status: 'unsupported',
    summary: `Scope '${input.scope}' is not supported. Use: products or dispatch.`,
    data: [],
    next_questions: [],
    safe_next_tools: []
  }
}];

