const input = $('Normalize Request').first().json;
const rows = $input.all().map(i => i.json).filter(r => r && r.id);

return [{
  json: {
    success: true,
    scope: 'products',
    operation: 'list',
    identity: {
      business_id: input.business_id || null,
      resolved: !!input.business_id,
      matched_by: 'business_id'
    },
    found: rows.length > 0,
    status: rows.length > 0 ? 'ok' : 'not_found',
    summary: rows.length > 0
      ? `Found ${rows.length} product(s).`
      : 'No products found matching that description.',
    data: rows.map(r => ({
      display_name:   r.display_name   || r.product_name,
      canonical_name: r.canonical_name || null,
      minio_url:      r.minio_url,
      category:       r.category       || null,
      image_type:     r.image_type,
      sort_order:     r.sort_order,
      price:          r.price          || null,
      price_label:    r.price_label    || null,
      is_available:   r.is_available,
      mime_type:      r.mime_type
    })),
    next_questions: rows.length === 0
      ? ['Ask if the user wants to upload product images.']
      : [],
    safe_next_tools: []
  }
}];

const input = $('Normalize Request').first().json;

return [{
  json: {
    success: true,
    scope: 'dispatch',
    operation: input.operation,
    identity: {
      business_id: input.business_id || null,
      resolved: !!input.business_id,
      matched_by: 'business_id'
    },
    found: false,
    status: 'unsupported',
    summary: `Dispatch operation '${input.operation}' is not supported. Use: lookup_order or list_recent.`,
    data: [],
    next_questions: [],
    safe_next_tools: []
  }
}];

const input = $('Normalize Request').first().json;

return [{
  json: {
    success: true,
    scope: 'dispatch',
    operation: 'lookup_order',
    identity: {
      business_id: input.business_id || null,
      resolved: !!input.business_id,
      matched_by: 'business_id'
    },
    found: false,
    status: 'missing_input',
    summary: 'Provide a shipment id, order number, tracking number, or a short dispatch reference.',
    data: [],
    next_questions: [
      'Ask for the shipment ID, order number, tracking number, destination city, carrier, or item name.'
    ],
    safe_next_tools: []
  }
}];

const input = $('Normalize Request').first().json;
const rows = $input.all().map(item => item.json).filter(row => row && row.id);

function parseJson(value) {
  if (!value) return {};
  if (typeof value === 'object') return value;
  try {
    return JSON.parse(value);
  } catch {
    return {};
  }
}

function normalizeRow(row) {
  const delivery = parseJson(row.delivery_address);
  const parcel = parseJson(row.parcel_info);

  return {
    shipment_id: row.shipment_id,
    order_number: parcel.order_number || null,
    carrier: row.carrier_name || null,
    status: row.status || null,
    payment_status: row.payment_status || null,
    payment_method: row.payment_method || null,
    tracking_number: row.tracking_number || null,
    tracking_url: row.tracking_url || null,
    amount: row.amount ?? null,
    item_name: parcel.item_name || null,
    recipient_name: delivery.name || delivery.recipient_name || null,
    recipient_phone: delivery.phone || delivery.recipient_phone || null,
    destination_city: delivery.city || null,
    destination_text: [
      delivery.address,
      delivery.city,
      delivery.state
    ].filter(Boolean).join(', ') || null,
    created_at: row.created_at || null,
    updated_at: row.updated_at || null
  };
}

if (rows.length === 0) {
  return [{
    json: {
      success: true,
      scope: 'dispatch',
      operation: 'lookup_order',
      identity: {
        business_id: input.business_id || null,
        resolved: !!input.business_id,
        matched_by: 'business_id'
      },
      found: false,
      status: 'not_found',
      summary: 'No dispatch order matched that reference.',
      data: [],
      next_questions: [
        'Ask for a shipment ID, tracking number, order number, destination city, or item name.'
      ],
      safe_next_tools: []
    }
  }];
}

if (rows.length > 1) {
  return [{
    json: {
      success: true,
      scope: 'dispatch',
      operation: 'lookup_order',
      identity: {
        business_id: input.business_id || null,
        resolved: !!input.business_id,
        matched_by: 'business_id'
      },
      found: true,
      status: 'ambiguous',
      summary: `Found ${rows.length} matching dispatch orders. Clarification needed.`,
      data: rows.map(normalizeRow).map(row => ({
        shipment_id: row.shipment_id,
        order_number: row.order_number,
        carrier: row.carrier,
        status: row.status,
        tracking_number: row.tracking_number,
        destination_city: row.destination_city,
        item_name: row.item_name,
        created_at: row.created_at
      })),
      next_questions: [
        'Ask which shipment they mean using shipment ID, order number, carrier, destination, or date.'
      ],
      safe_next_tools: []
    }
  }];
}

const match = normalizeRow(rows[0]);

return [{
  json: {
    success: true,
    scope: 'dispatch',
    operation: 'lookup_order',
    identity: {
      business_id: input.business_id || null,
      resolved: !!input.business_id,
      matched_by: 'business_id'
    },
    found: true,
    status: 'ok',
    summary: `Found dispatch order ${match.shipment_id}${match.order_number ? ` for ${match.order_number}` : ''}.`,
    data: match,
    next_questions: [],
    safe_next_tools: ['Terminal_Track Dispatch']
  }
}];

