    found: data.length > 0,
    status: data.length > 0 ? 'ok' : 'not_found',
    summary: data.length > 0
      ? `Found ${data.length} recent dispatch order(s).`
      : 'No dispatch orders found for this business.',
    data,
    next_questions: data.length === 0
